-- === Lecons (brouillon) ===
insert into lessons (slug, title, summary, chapter_id, subchapter_id, sort_order, status, is_free_preview)
select v.slug, v.title, v.summary, c.id, sc.id, v.sort_order, 'draft', false from (values
('6eme-svt-1-s1-l1', 'Le matériel nécessaire pour une sortie de terrain', 'Rechercher le matériel utile à une sortie : carnet de notes, crayon, couteau et contenants de collecte.', '6eme-svt-1', '6eme-svt-1-s1', 1),
('6eme-svt-1-s1-l2', 'La préparation de la collecte des données de terrain', 'Préparer les fiches de notation des êtres vivants et de relevé des caractéristiques physiques et chimiques du milieu.', '6eme-svt-1', '6eme-svt-1-s1', 2),
('6eme-svt-1-s1-l3', 'La rédaction du compte rendu de sortie', 'Apprendre la technique de rédaction d''un compte rendu de sortie en remplissant un canevas.', '6eme-svt-1', '6eme-svt-1-s1', 3),
('6eme-svt-1-s2-l1', 'Les composantes d''un milieu', 'Identifier les êtres vivants et les caractéristiques physiques et chimiques qui composent un milieu.', '6eme-svt-1', '6eme-svt-1-s2', 4),
('6eme-svt-1-s2-l2', 'Les relations entre les êtres vivants et leur milieu', 'Mettre en évidence les relations entre les êtres vivants et entre les êtres vivants et leur milieu de vie.', '6eme-svt-1', '6eme-svt-1-s2', 5),
('6eme-svt-1-s3-l1', 'Les différents modes de déplacement des animaux', 'Découvrir les modes de déplacement des animaux : la marche, le vol, la nage, le saut et la reptation.', '6eme-svt-1', '6eme-svt-1-s3', 6),
('6eme-svt-1-s3-l2', 'Les organes et structures adaptés au déplacement', 'Étudier les organes et structures adaptés à chaque mode de déplacement, en se limitant à la morphologie.', '6eme-svt-1', '6eme-svt-1-s3', 7),
('6eme-svt-1-s3-l3', 'L''intérêt du déplacement pour les animaux', 'Expliquer pourquoi certains animaux se déplacent : recherche de nourriture, d''abri et de partenaire sexuel.', '6eme-svt-1', '6eme-svt-1-s3', 8),
('6eme-svt-2-s1-l1', 'Les règles d''hygiène du milieu, corporelle et alimentaire', 'S''informer sur les règles d''hygiène du milieu, de l''hygiène corporelle et de l''hygiène alimentaire.', '6eme-svt-2', '6eme-svt-2-s1', 1),
('6eme-svt-2-s1-l2', 'Les bonnes pratiques d''hygiène au quotidien', 'Pratiquer le lavage du corps et des mains, l''entretien du milieu de vie et la conservation des aliments.', '6eme-svt-2', '6eme-svt-2-s1', 2),
('6eme-svt-2-s1-l3', 'La sensibilisation à une bonne hygiène', 'Élaborer des supports comme des textes et des affiches pour sensibiliser à une bonne pratique de l''hygiène.', '6eme-svt-2', '6eme-svt-2-s1', 3),
('6eme-svt-2-s2-l1', 'La vaccination et le calendrier vaccinal', 'Comprendre la vaccination et lire le calendrier de vaccination inscrit dans le carnet de santé.', '6eme-svt-2', '6eme-svt-2-s2', 4),
('6eme-svt-2-s2-l2', 'Les vaccins obligatoires et les maladies évitées', 'Connaître les vaccins obligatoires (DTCoq-Polio, anti-rougeoleux, BCG, anti amaril) et les maladies infectieuses évitées.', '6eme-svt-2', '6eme-svt-2-s2', 5),
('6eme-svt-2-s2-l3', 'L''importance de la vaccination et la sensibilisation', 'Expliquer l''intérêt des vaccins pour l''Homme et les animaux et proposer des supports de sensibilisation.', '6eme-svt-2', '6eme-svt-2-s2', 6),
('6eme-svt-2-s3-l1', 'Les différentes drogues connues', 'S''informer sur les drogues courantes : alcool, tabac, cannabis, cocaïne et drogues de synthèse.', '6eme-svt-2', '6eme-svt-2-s3', 7),
('6eme-svt-2-s3-l2', 'Les méfaits des drogues sur l''individu', 'Relever les effets immédiats et à long terme des drogues : euphorie, hallucination, addiction, cancers et cirrhose.', '6eme-svt-2', '6eme-svt-2-s3', 8),
('6eme-svt-2-s3-l3', 'Les conséquences sociales de l''usage des drogues', 'Identifier les conséquences sociales des drogues : querelles, violence, divorce, misère, criminalité et vol.', '6eme-svt-2', '6eme-svt-2-s3', 9),
('6eme-svt-2-s3-l4', 'La sensibilisation aux méfaits des drogues', 'Proposer des supports comme des textes et affiches pour sensibiliser aux méfaits des drogues dans son milieu.', '6eme-svt-2', '6eme-svt-2-s3', 10),
('6eme-svt-2-s4-l1', 'Les IST et le VIH-SIDA : définitions', 'S''informer sur les IST (gonococcie, chancre mou, syphilis) et le VIH-SIDA et leur signification.', '6eme-svt-2', '6eme-svt-2-s4', 11),
('6eme-svt-2-s4-l2', 'Les voies de contamination des IST et du VIH-SIDA', 'Distinguer la voie sexuelle des IST et les voies sexuelle, sanguine et mère-enfant du VIH-SIDA.', '6eme-svt-2', '6eme-svt-2-s4', 12),
('6eme-svt-2-s4-l3', 'Les comportements à risque', 'Décrire les comportements à risque : rapports non protégés, partenaires multiples et matériel souillé de sang.', '6eme-svt-2', '6eme-svt-2-s4', 13),
('6eme-svt-2-s4-l4', 'La sensibilisation contre les IST/VIH-SIDA', 'Proposer des supports comme des textes et affiches sur les comportements à risque de contamination.', '6eme-svt-2', '6eme-svt-2-s4', 14),
('6eme-svt-2-s5-l1', 'Les symptômes du paludisme', 'Reconnaître les symptômes du paludisme : maux de tête, fièvre, fatigue, manque d''appétit, frissons et insomnie.', '6eme-svt-2', '6eme-svt-2-s5', 15),
('6eme-svt-2-s5-l2', 'Le vecteur et l''agent pathogène du paludisme', 'Identifier l''agent vecteur, l''anophèle femelle, et l''agent pathogène, le plasmodium.', '6eme-svt-2', '6eme-svt-2-s5', 16),
('6eme-svt-2-s5-l3', 'Le traitement et la prévention du paludisme', 'Connaître le traitement par antipaludéens prescrits et les moyens de prévention comme la moustiquaire imprégnée.', '6eme-svt-2', '6eme-svt-2-s5', 17),
('6eme-svt-3-s1-l1', 'Les divers modes d''alimentation des animaux', 'S''informer sur les régimes alimentaires : omnivores, carnivores, herbivores, insectivores, frugivores et granivores.', '6eme-svt-3', '6eme-svt-3-s1', 1),
('6eme-svt-3-s1-l2', 'Le lien entre le régime alimentaire et l''appareil digestif', 'Comparer les appareils digestifs de l''Homme, d''un ruminant et d''un granivore selon leur régime alimentaire.', '6eme-svt-3', '6eme-svt-3-s1', 2),
('6eme-svt-3-s1-l3', 'Le rôle des aliments dans la vie des animaux', 'Déterminer le rôle des aliments : production d''énergie, survie, croissance et reproduction.', '6eme-svt-3', '6eme-svt-3-s1', 3),
('6eme-svt-3-s2-l1', 'Les différents types et lieux d''élevage des animaux', 'S''informer sur l''élevage de volailles, caprins, ovins et bovins, à domicile ou dans une ferme.', '6eme-svt-3', '6eme-svt-3-s2', 4),
('6eme-svt-3-s2-l2', 'L''importance de l''élevage des animaux', 'Déterminer l''importance de l''élevage : production de viande, développement économique et recyclage de la matière.', '6eme-svt-3', '6eme-svt-3-s2', 5),
('6eme-svt-3-s2-l3', 'Les exemples d''élevage avantageux dans son milieu', 'Proposer des élevages avantageux : volailles, porcs, caprins et abeilles adaptés à son milieu.', '6eme-svt-3', '6eme-svt-3-s2', 6),
('6eme-svt-4-s1-l1', 'La reproduction par les œufs chez la poule', 'Découvrir l''oviparité chez la poule : reproduction par les œufs, couvaison et développement des poussins.', '6eme-svt-4', '6eme-svt-4-s1', 1),
('6eme-svt-4-s1-l2', 'Les comportements sexuels du coq et de la poule', 'Décrire le dimorphisme sexuel et les comportements du coq (parade, chant, combat) et de la poule.', '6eme-svt-4', '6eme-svt-4-s1', 2),
('6eme-svt-4-s1-l3', 'L''origine et l''évolution de l''œuf', 'Expliquer l''origine et l''évolution de l''œuf à l''aide du schéma de sa coupe longitudinale.', '6eme-svt-4', '6eme-svt-4-s1', 3),
('6eme-svt-4-s1-l4', 'L''élevage des poules', 'Apprendre à élever les volailles : construction du poulailler, choix des géniteurs et recherche de nourriture.', '6eme-svt-4', '6eme-svt-4-s1', 4),
('6eme-svt-4-s2-l1', 'La reproduction chez l''Homme : la viviparité', 'Découvrir la viviparité chez l''Homme : grossesse, accouchement, lactation et soins au nouveau-né.', '6eme-svt-4', '6eme-svt-4-s2', 5),
('6eme-svt-4-s2-l2', 'Les caractères sexuels primaires et secondaires', 'Décrire les caractères sexuels de l''enfance à l''adolescence chez le garçon et chez la fille.', '6eme-svt-4', '6eme-svt-4-s2', 6),
('6eme-svt-4-s2-l3', 'La fécondation et l''évolution de la grossesse', 'Expliquer la fécondation, naturelle ou artificielle, et l''évolution de la grossesse jusqu''à l''accouchement.', '6eme-svt-4', '6eme-svt-4-s2', 7),
('6eme-svt-4-s2-l4', 'La prévention des grossesses précoces', 'Comprendre comment prévenir les grossesses précoces par l''abstinence et l''évitement des rapports non protégés.', '6eme-svt-4', '6eme-svt-4-s2', 8),
('5eme-svt-1-s1-l1', 'Identifier les polluants solides de son environnement', 'Reconnaître les polluants solides du milieu : sachets, bouteilles, plastiques, piles, écrans et résidus miniers.', '5eme-svt-1', '5eme-svt-1-s1', 1),
('5eme-svt-1-s1-l2', 'L''impact des polluants solides sur l''environnement', 'Comprendre l''infiltration difficile de l''eau, les inondations et la multiplication des gîtes larvaires de moustiques.', '5eme-svt-1', '5eme-svt-1-s1', 2),
('5eme-svt-1-s1-l3', 'Des solutions pour réduire l''impact des polluants solides', 'Collecte et tri des ordures, refus de l''incinération, recyclage des plastiques et métaux, matériaux biodégradables.', '5eme-svt-1', '5eme-svt-1-s1', 3),
('5eme-svt-1-s2-l1', 'Les maillons d''une chaîne alimentaire et le réseau trophique', 'Identifier producteurs, consommateurs et décomposeurs à travers la question qui mange qui.', '5eme-svt-1', '5eme-svt-1-s2', 4),
('5eme-svt-1-s2-l2', 'L''importance de la chaîne alimentaire dans l''équilibre de la nature', 'Montrer l''interdépendance des êtres vivants, l''équilibre de la nature et le recyclage de la matière.', '5eme-svt-1', '5eme-svt-1-s2', 5),
('5eme-svt-1-s3-l1', 'Le régime alimentaire des animaux d''élevage', 'Décrire l''alimentation des volailles, caprins, ovins, bovins, poissons, porcins et lapins.', '5eme-svt-1', '5eme-svt-1-s3', 6),
('5eme-svt-1-s3-l2', 'Choisir l''élevage économiquement avantageux selon la région', 'Proposer les élevages rentables selon la région : volailles, poissons, porcins, caprins, ovins, abeilles.', '5eme-svt-1', '5eme-svt-1-s3', 7),
('5eme-svt-2-s1-l1', 'Les aliments consommés localement', 'Recenser céréales, haricots, soja, tubercules, oléagineux, œufs, poissons, viandes, fruits, légumes et lait.', '5eme-svt-2', '5eme-svt-2-s1', 1),
('5eme-svt-2-s1-l2', 'Le rôle de chaque aliment dans l''organisme', 'Distinguer les aliments de croissance, d''apport d''énergie et de protection ou équilibre fonctionnel.', '5eme-svt-2', '5eme-svt-2-s1', 2),
('5eme-svt-2-s1-l3', 'Composer une alimentation équilibrée à partir des aliments du milieu', 'Établir les rations de croissance, de travail et de protection à partir des aliments disponibles.', '5eme-svt-2', '5eme-svt-2-s1', 3),
('5eme-svt-2-s2-l1', 'Les principales maladies parasitaires', 'Citer ascaridiose, paludisme, amibiase, dracunculose, filariose, cysticercose et schistosomiase.', '5eme-svt-2', '5eme-svt-2-s2', 4),
('5eme-svt-2-s2-l2', 'Les symptômes de l''ascaridiose et son parasite', 'Décrire toux sèche, troubles digestifs et fatigue générale, causés par le parasite ascaris.', '5eme-svt-2', '5eme-svt-2-s2', 5),
('5eme-svt-2-s2-l3', 'Les mesures de prévention contre l''ascaridiose', 'Se laver les mains, laver les aliments, utiliser les latrines et désinfecter l''eau de boisson.', '5eme-svt-2', '5eme-svt-2-s2', 6),
('5eme-svt-2-s3-l1', 'Le VIH-SIDA : définitions, maladies opportunistes et voies de transmission', 'Définir VIH et SIDA, présenter les maladies opportunistes et les voies sexuelle et non sexuelle.', '5eme-svt-2', '5eme-svt-2-s3', 7),
('5eme-svt-2-s3-l2', 'Les comportements à risque d''infection au VIH-SIDA', 'Rapport non protégé, réutilisation d''aiguilles, absence de gants, prostitution et drogues injectables.', '5eme-svt-2', '5eme-svt-2-s3', 8),
('5eme-svt-3-s1-l1', 'Les besoins nutritifs et facteurs de développement des plantes vertes', 'Identifier eau, sels minéraux, dioxyde de carbone, lumière et température comme facteurs de développement.', '5eme-svt-3', '5eme-svt-3-s1', 1),
('5eme-svt-3-s1-l2', 'Des expériences sur les besoins en eau des plantes vertes', 'Comparer une plante dont les racines sont dans l''eau et une plante dont les racines en sont privées.', '5eme-svt-3', '5eme-svt-3-s1', 2),
('5eme-svt-3-s1-l3', 'Les tissus d''absorption et de conduction de la sève', 'Situer la racine, la zone pilifère, le xylème de la sève brute et le phloème de la sève élaborée.', '5eme-svt-3', '5eme-svt-3-s1', 3),
('5eme-svt-3-s1-l4', 'La culture de fleurs et de légumes', 'Réaliser des cultures de fleurs en pots ou en pleine terre et des jardins potagers et maraîchers.', '5eme-svt-3', '5eme-svt-3-s1', 4),
('5eme-svt-3-s2-l1', 'La photosynthèse : la synthèse de l''amidon par les plantes vertes', 'Présenter la photosynthèse comme la fabrication de l''amidon par les plantes vertes.', '5eme-svt-3', '5eme-svt-3-s2', 5),
('5eme-svt-3-s2-l2', 'Les conditions et facteurs nécessaires à la fabrication de l''amidon', 'Mettre en évidence le rôle de la lumière, de l''eau, du dioxyde de carbone, de la chlorophylle et des sels minéraux.', '5eme-svt-3', '5eme-svt-3-s2', 6),
('5eme-svt-3-s2-l3', 'L''intérêt des plantes vertes dans la nature', 'Assainissement de l''atmosphère, production de matière organique, protection du sol et régulation du climat.', '5eme-svt-3', '5eme-svt-3-s2', 7),
('5eme-svt-4-s1-l1', 'La reproduction sexuée chez les animaux et les végétaux : notions générales', 'Distinguer mâle, femelle et hermaphrodite chez l''animal, spores et fleurs chez les végétaux.', '5eme-svt-4', '5eme-svt-4-s1', 1),
('5eme-svt-4-s1-l2', 'Les étapes de la reproduction sexuée et le cycle de reproduction', 'Décrire gamètes, fécondation et évolution de l''œuf, puis schématiser le cycle de reproduction.', '5eme-svt-4', '5eme-svt-4-s1', 2),
('5eme-svt-4-s2-l1', 'Les causes des grossesses précoces chez les adolescentes', 'Distinguer les causes directes, comme les rapports non protégés, et les causes indirectes.', '5eme-svt-4', '5eme-svt-4-s2', 3),
('5eme-svt-4-s2-l2', 'Les conséquences d''une grossesse précoce sur la fille et la société', 'Présenter les conséquences sur la santé de la mère, sur celle de l''enfant et les conséquences sociales.', '5eme-svt-4', '5eme-svt-4-s2', 4),
('5eme-svt-4-s2-l3', 'Les actions de prévention des grossesses précoces en milieu scolaire', 'Éviter les rapports non protégés, participer aux campagnes et élaborer des supports de sensibilisation.', '5eme-svt-4', '5eme-svt-4-s2', 5),
('5eme-svt-4-s3-l1', 'La reproduction asexuée chez les animaux et les végétaux', 'Reconnaître les cas d''amibes et paramécies et des végétaux comme manioc, patate, taro, banane et igname.', '5eme-svt-4', '5eme-svt-4-s3', 6),
('5eme-svt-4-s3-l2', 'La reproduction asexuée de l''amibe et de la paramécie', 'Décrire la division de l''amibe en deux, puis en quatre, et ainsi de suite.', '5eme-svt-4', '5eme-svt-4-s3', 7),
('5eme-svt-4-s3-l3', 'La multiplication végétative des plantes', 'Produire des plantes par bouturage, drageonnage, marcottage et greffage.', '5eme-svt-4', '5eme-svt-4-s3', 8),
('5eme-svt-5-s1-l1', 'Les types de sols et leurs caractéristiques', 'Reconnaître sols sableux, argileux, limoneux, latéritiques et humifères, meubles ou compacts.', '5eme-svt-5', '5eme-svt-5-s1', 1),
('5eme-svt-5-s1-l2', 'Les propriétés d''un sol', 'Décrire perméabilité, capacité de rétention en eau, texture, porosité et teneur en humus.', '5eme-svt-5', '5eme-svt-5-s1', 2),
('5eme-svt-5-s1-l3', 'Relation entre les exigences d''une plante et les caractéristiques du sol', 'Relier les végétaux d''un milieu à la nature du sol et aborder l''amendement en agriculture.', '5eme-svt-5', '5eme-svt-5-s1', 3),
('5eme-svt-5-s2-l1', 'Les causes de la dégradation des sols', 'Distinguer la dégradation naturelle liée au climat et celle due à l''action de l''Homme.', '5eme-svt-5', '5eme-svt-5-s2', 4),
('5eme-svt-5-s2-l2', 'Les actions du climat et de l''Homme dans la dégradation du sol', 'Décrire l''action de l''eau et du vent, le déboisement, les feux et l''exploitation minière.', '5eme-svt-5', '5eme-svt-5-s2', 5),
('5eme-svt-5-s2-l3', 'La sensibilisation à la protection des sols', 'Élaborer des supports, reboiser, pratiquer l''agroforesterie et la culture en terrasses.', '5eme-svt-5', '5eme-svt-5-s2', 6),
('5eme-svt-5-s3-l1', 'L''agriculture en lien avec la nature du sol', 'Relier cultures vivrières et cultures d''exportation à la nature du sol.', '5eme-svt-5', '5eme-svt-5-s3', 7),
('5eme-svt-5-s3-l2', 'Les sols favorables et défavorables à la production agricole', 'Opposer les sols riches en humus aux sols pauvres, lessivés, ferrugineux ou argileux.', '5eme-svt-5', '5eme-svt-5-s3', 8),
('5eme-svt-5-s3-l3', 'Les techniques d''amendement des sols', 'Utiliser engrais verts, paillage, légumineuses, fumier, compost et semences sélectionnées.', '5eme-svt-5', '5eme-svt-5-s3', 9),
('4eme-svt-1-s1-l1', 'Les types de polluants chimiques', 'Identifie les polluants solides, liquides et gazeux présents dans l''environnement local.', '4eme-svt-1', '4eme-svt-1-s1', 1),
('4eme-svt-1-s1-l2', 'Impacts des polluants sur la biodiversité et la santé', 'Explique la perturbation de la biodiversité et les maladies causées par les polluants chimiques.', '4eme-svt-1', '4eme-svt-1-s1', 2),
('4eme-svt-1-s1-l3', 'Solutions pour remédier aux méfaits des polluants', 'Propose des mesures comme les engrais verts, les matières biodégradables et la sensibilisation.', '4eme-svt-1', '4eme-svt-1-s1', 3),
('4eme-svt-1-s2-l1', 'Les différents types de ressources naturelles', 'Distingue les ressources renouvelables, non renouvelables et altérables.', '4eme-svt-1', '4eme-svt-1-s2', 4),
('4eme-svt-1-s2-l2', 'Mesures pour une gestion durable des ressources au Togo', 'Présente la réglementation, la sensibilisation et le reboisement pour préserver les ressources.', '4eme-svt-1', '4eme-svt-1-s2', 5),
('4eme-svt-2-s1-l1', 'Collecter et reconnaître les roches de sa localité', 'Recense les échantillons de roches courants comme sables, argiles, calcaires et granites.', '4eme-svt-2', '4eme-svt-2-s1', 1),
('4eme-svt-2-s1-l2', 'Distinguer les roches collectées', 'Observe l''aspect macroscopique, la composition minéralogique et la texture des roches.', '4eme-svt-2', '4eme-svt-2-s1', 2),
('4eme-svt-2-s1-l3', 'Classification simple des roches', 'Classe les roches en sédimentaires, magmatiques et métamorphiques dans un tableau simple.', '4eme-svt-2', '4eme-svt-2-s1', 3),
('4eme-svt-2-s2-l1', 'Les causes de l''érosion et de l''altération des roches', 'Recense le rôle de l''eau, du vent, des racines et des actions humaines dans l''érosion.', '4eme-svt-2', '4eme-svt-2-s2', 4),
('4eme-svt-2-s2-l2', 'Les étapes de l''érosion et de l''altération', 'Décrit le chaos granitique, l''arène granitique, l''érosion mécanique et l''altération chimique.', '4eme-svt-2', '4eme-svt-2-s2', 5),
('4eme-svt-2-s2-l3', 'Sensibilisation pour réduire l''érosion et l''altération', 'Propose reboisement, agroforesterie et culture en terrasses pour limiter l''érosion.', '4eme-svt-2', '4eme-svt-2-s2', 6),
('4eme-svt-2-s3-l1', 'Les différentes roches sédimentaires', 'Recense les roches sédimentaires comme sables, argiles, calcaires, grès et gypse.', '4eme-svt-2', '4eme-svt-2-s3', 7),
('4eme-svt-2-s3-l2', 'Les étapes de formation des roches sédimentaires', 'Décrit l''érosion, le transport, le dépôt et la diagenèse conduisant aux roches sédimentaires.', '4eme-svt-2', '4eme-svt-2-s3', 8),
('4eme-svt-3-s1-l1', 'Causes, agents et symptômes de la tuberculose', 'Présente le bacille de Koch, le mode de transmission et les symptômes de la tuberculose.', '4eme-svt-3', '4eme-svt-3-s1', 1),
('4eme-svt-3-s1-l2', 'Facteurs favorisant la propagation', 'Identifie le nomadisme, la poussière, la mauvaise hygiène et la promiscuité comme facteurs de propagation.', '4eme-svt-3', '4eme-svt-3-s1', 2),
('4eme-svt-3-s1-l3', 'Moyens de prévention de la tuberculose', 'Présente la vaccination au BCG, le dépistage et une bonne hygiène sanitaire.', '4eme-svt-3', '4eme-svt-3-s1', 3),
('4eme-svt-3-s2-l1', 'Symptômes, causes et voies de transmission de la Covid-19', 'Décrit le coronavirus, les symptômes et la transmission par gouttelettes et contact.', '4eme-svt-3', '4eme-svt-3-s2', 4),
('4eme-svt-3-s2-l2', 'Moyens de prévention et mesures barrières', 'Présente le lavage des mains, le port du masque et la distanciation contre la Covid-19.', '4eme-svt-3', '4eme-svt-3-s2', 5),
('4eme-svt-3-s2-l3', 'Supports de sensibilisation sur la Covid-19', 'Élabore affiches, textes et chansons pour les campagnes de sensibilisation.', '4eme-svt-3', '4eme-svt-3-s2', 6),
('4eme-svt-3-s3-l1', 'Causes, symptômes et phases du paludisme', 'Présente le plasmodium, le moustique vecteur, les symptômes et les phases de la maladie.', '4eme-svt-3', '4eme-svt-3-s3', 7),
('4eme-svt-3-s3-l2', 'Moyens de prévention contre le paludisme', 'Présente les mesures collectives et individuelles pour se protéger du paludisme.', '4eme-svt-3', '4eme-svt-3-s3', 8),
('4eme-svt-4-s1-l1', 'Les volcans et leurs effets', 'Présente les produits, les étapes d''une éruption et les effets du volcanisme sur le milieu.', '4eme-svt-4', '4eme-svt-4-s1', 1),
('4eme-svt-4-s1-l2', 'Localisation des grandes zones volcaniques', 'Situe les zones volcaniques du globe et leur relation avec les séismes.', '4eme-svt-4', '4eme-svt-4-s1', 2),
('4eme-svt-4-s1-l3', 'Intérêt scientifique de l''étude des éruptions volcaniques', 'Explique l''apport des éruptions à la connaissance des magmas et de la structure terrestre.', '4eme-svt-4', '4eme-svt-4-s1', 3),
('4eme-svt-4-s1-l4', 'Comportements à adopter en cas de catastrophe naturelle', 'Vulgarise l''observation, l''écoute des médias et l''appel des secours en cas de catastrophe.', '4eme-svt-4', '4eme-svt-4-s1', 4),
('4eme-svt-4-s2-l1', 'Les roches magmatiques : échantillons et caractéristiques', 'Recense granite et basalte, leurs aspects macroscopiques et leur composition.', '4eme-svt-4', '4eme-svt-4-s2', 5),
('4eme-svt-4-s2-l2', 'Mode de formation des roches magmatiques', 'Explique le refroidissement du magma pour les roches plutoniques et volcaniques.', '4eme-svt-4', '4eme-svt-4-s2', 6),
('4eme-svt-4-s3-l1', 'Les roches métamorphiques : échantillons et caractéristiques', 'Recense gneiss et quartzites, leurs aspects macroscopiques et leur composition.', '4eme-svt-4', '4eme-svt-4-s3', 7),
('4eme-svt-4-s3-l2', 'Mode de formation des roches métamorphiques', 'Explique la recristallisation à l''état solide sous l''effet de la température et de la pression.', '4eme-svt-4', '4eme-svt-4-s3', 8),
